OOSI v3 magic: first 4 bytes = 0x4F4F5333 ('OOS3' in little-endian ASCII).
OOSI v2 magic: 0x4F4F5353 ('OOSS').

Detection in llmk_detect_model_format() (soma_mind.c):
```c
LlmkModelFormat llmk_detect_model_format(EFI_FILE_PROTOCOL *f) {
    UINT8 magic[4];
    UINTN sz = 4;
    f->Read(f, &sz, magic);
    if (magic[0]=='O' && magic[1]=='O' && magic[2]=='S' && magic[3]=='3')
        return LLMK_MODEL_FMT_OOSI3;
    if (magic[0]=='O' && magic[1]=='O' && magic[2]=='S' && magic[3]=='S')
        return LLMK_MODEL_FMT_OOSI2;
    // Fallback: GGUF or legacy .bin
    if (magic[0]==0x47 && magic[1]==0x47 && magic[2]==0x55 && magic[3]==0x46)
        return LLMK_MODEL_FMT_GGUF;
    return LLMK_MODEL_FMT_BIN;
}
```

v3 boot path uses goto oosi3_boot_done to skip the 7×sizeof(int) .bin header parse entirely, avoiding Config struct corruption. OOSI3 weights are lazy-loaded on first /think call.

DjibLAS provides zero-malloc, UEFI-safe matmul:

```c
// Core API
void djiblas_matmul_f32(
    const float *A,   // [M x K] row-major
    const float *B,   // [K x N] row-major
    float       *C,   // [M x N] output (pre-allocated by caller)
    int M, int K, int N
);

// Fused matmul + bias + activation
void djiblas_matmul_bias_relu(
    const float *A, const float *B, const float *bias,
    float *C, int M, int K, int N
);

// AVX2 hot path (auto-selected when djiblas_init() detects AVX2)
void djiblas_matmul_f32_avx2(
    const float *A, const float *B, float *C, int M, int K, int N
);
```

Key rules for bare-metal:
- Caller pre-allocates C from a ZONE_COMPUTE scratch buffer
- No internal malloc() — all temporaries use stack-allocated 32-byte aligned arrays
- djiblas_init() calls CPUID to detect AVX2/AVX512 and sets function pointers
- In UEFI context: call before ExitBootServices() to benefit from BIOS-initialized cache

DjibMark is an execution tracing library for freestanding C11. It uses no libc, no OS calls:

```c
// Trace a named scope (stores in static ring buffer)
DJIBMARK_BEGIN("inference_step");
  djiblas_matmul_f32(...);
DJIBMARK_END("inference_step");

// Dump trace to EFI serial (COM1) or UEFI ConOut
djibmark_dump_serial();
djibmark_dump_conout(SystemTable->ConOut);
```

Internals:
- Static ring buffer: djibmark_entry[DJIBMARK_MAX_ENTRIES] (default 256)
- Timestamps via RDTSC (raw TSC counter, no calibration needed for relative timing)
- Each entry: name (char[32]), tsc_start, tsc_end, depth (call stack level)
- djibmark_begin() stores RDTSC into entry, pushes to stack
- djibmark_end() pops, computes delta_tsc, stores in ring buffer
- Zero heap: all state in BSS section — safe in UEFI pre-ExitBootServices

soma_warden.c adds semantic threat scanning on top of llmk_sentinel:

```c
// Called after every oosi_v3_generate() token batch
int soma_warden_scan(const char *output, size_t len) {
    // Phase 1: pattern matching (fast, O(n) scan)
    for (int i = 0; i < WARDEN_RULE_COUNT; i++) {
        if (strstr_nocase(output, warden_rules[i].pattern)) {
            warden_rule_hits[i]++;
            llmk_sentinel_add_pressure(warden_rules[i].pressure_delta);
        }
    }
    // Phase 2: session threat accumulation
    if (session_rule_hit_count >= WARDEN_ESCALATION_THRESHOLD) {
        // 3+ different rules triggered → escalate to QUARANTINE
        oo_dplus_set_verdict(VERDICT_QUARANTINE, "warden_semantic_escalation");
        soma_warden_emit_bus_alert("semantic_escalation", current_pressure);
        return -1;
    }
    return 0;
}
```

Every warden decision emits a diops_event(kind=warden_alert) to the OO bus:
```json
{"kind":"diops_event","worker":"warden","status":"alert","summary":"rule=<NAME> hits=<N> pressure=<P>"}
```
oo-bot receives this and can trigger governance responses via react_to_messages().

soma_swarm.c quorum formula:
```c
#define OO_QUORUM_FRACTION_NUM 2
#define OO_QUORUM_FRACTION_DEN 3

bool soma_swarm_quorum_ok(const OoSwarmState *s) {
    int active = 0;
    for (int i = 0; i < s->node_count; i++)
        if (s->nodes[i].state == OO_NODE_ACTIVE ||
            s->nodes[i].state == OO_NODE_SYNCING)
            active++;
    return (active * OO_QUORUM_FRACTION_DEN) >=
           (s->node_count * OO_QUORUM_FRACTION_NUM);
}
```

Quorum loss cascade:
1. soma_swarm detects quorum_ok = false
2. Emits SwarmEvent{quorum_degraded=true, active=N, total=M} via UART bus
3. oo-host swarm coordinator receives → BotBusState.swarm_quorum_degraded = true
4. oo-bot emit_swarm_alert() → Governor (kind=swarm_alert, node_state=DEGRADED)
5. D+ gate: if quorum_degraded → raise pressure by DPLUS_QUORUM_PRESSURE_BOOST (default 20)
6. Organism transitions to OO_NODE_DEGRADED, soma HUD ring turns amber

Morphion monitors hermes bus channel health scores. When a module's health_score drops below MORPHION_REROUTE_THRESHOLD (0.3) for MORPHION_MIN_CYCLES (3) consecutive cycles:

```c
void morphion_evaluate(const OoModuleHealth *health, int n) {
    for (int i = 0; i < n; i++) {
        if (health[i].score < MORPHION_REROUTE_THRESHOLD)
            health[i].consecutive_low++;
        else
            health[i].consecutive_low = 0;

        if (health[i].consecutive_low >= MORPHION_MIN_CYCLES) {
            // Propose reroute: requires D+ ALLOW verdict
            MorphionPatch p = morphion_build_reroute_patch(&health[i]);
            if (dplus_evaluate_patch(&p) == VERDICT_ALLOW)
                hermes_reroute_channel(health[i].name, p.new_target);
        }
    }
}
```

D+ integration: morphion_build_reroute_patch() creates a signed patch descriptor. dplus_evaluate_patch() checks: action='reroute_channel', severity='medium', not in blocked_actions list. Only ALLOW proceeds. All reroutes are logged with channel_name + old_target + new_target + dna_hash of approving state.

Synaption tracks co-activation timing between OO modules:

```c
#define SYNAPTION_CO_WINDOW_MS  50   // co-activation window
#define SYNAPTION_LEARN_RATE    0.05f
#define SYNAPTION_FORGET_RATE   0.01f // per cycle

typedef struct {
    char   mod_a[32], mod_b[32];
    float  weight;          // current channel weight
    uint32_t last_co_ts;    // last co-activation timestamp
    uint32_t fire_count;    // total co-activations
} SynapticEdge;

void synaption_on_fire(const char *mod_name, uint32_t ts_ms) {
    for (int i = 0; i < edge_count; i++) {
        SynapticEdge *e = &edges[i];
        bool matches_a = streq(e->mod_a, mod_name);
        bool matches_b = streq(e->mod_b, mod_name);
        if (!matches_a && !matches_b) continue;

        uint32_t delta = ts_ms - e->last_co_ts;
        if (delta < SYNAPTION_CO_WINDOW_MS) {
            // Hebbian strengthening
            e->weight = fminf(1.0f, e->weight + SYNAPTION_LEARN_RATE);
            e->fire_count++;
        }
        e->last_co_ts = ts_ms;
    }
}

void synaption_decay_cycle(void) {
    for (int i = 0; i < edge_count; i++)
        edges[i].weight = fmaxf(0.0f, edges[i].weight - SYNAPTION_FORGET_RATE);
}
```

Edge weights are applied as multipliers on hermes channel priorities. Pairs that consistently co-activate within 50ms develop strong synaptic bonds — effectively rewiring the organism's response patterns over time.

Symbion maintains a compact symbolic knowledge base:

```c
#define SYMBION_MAX_TRIPLES 256
#define SYMBION_STR_MAX     48

typedef struct {
    char subject[SYMBION_STR_MAX];
    char predicate[SYMBION_STR_MAX];
    char object[SYMBION_STR_MAX];
    uint8_t confidence;  // 0-100
} SymbionTriple;

static SymbionTriple g_triples[SYMBION_MAX_TRIPLES];
static int g_triple_count = 0;

// REPL commands:
// /assert threat access-to kernel
void symbion_assert(const char *s, const char *p, const char *o) {
    if (g_triple_count >= SYMBION_MAX_TRIPLES) symbion_evict_oldest();
    SymbionTriple *t = &g_triples[g_triple_count++];
    strncpy(t->subject, s, SYMBION_STR_MAX-1);
    strncpy(t->predicate, p, SYMBION_STR_MAX-1);
    strncpy(t->object, o, SYMBION_STR_MAX-1);
    t->confidence = 90;
}

// /query threat access-to *  → returns matching triples
int symbion_query(const char *s, const char *p, const char *o,
                  SymbionTriple **results, int max_results) {
    int n = 0;
    for (int i = 0; i < g_triple_count && n < max_results; i++) {
        bool ms = (!s || s[0]=='*' || streq(g_triples[i].subject, s));
        bool mp = (!p || p[0]=='*' || streq(g_triples[i].predicate, p));
        bool mo = (!o || o[0]=='*' || streq(g_triples[i].object, o));
        if (ms && mp && mo) results[n++] = &g_triples[i];
    }
    return n;
}
```

D+ policy rules use symbion_query() for semantic gating: if query('threat','access-to','kernel') returns results, pressure += DPLUS_SYMBOLIC_THREAT_BOOST.

Chronion is the OO temporal awareness engine:
```c
typedef struct {
    uint64_t boot_tsc;           // TSC at kernel entry
    uint32_t continuity_epoch;   // persisted across reboots in soma_dna.bin
    uint32_t infer_count;        // total /think calls this session
    uint32_t last_infer_ts;      // epoch-s of last inference
    // Temporal heatmap: 24 hourly slots (uses CMOS RTC if available)
    uint16_t activity_heatmap[24];
} ChronionState;
```

Rhythm detection (called after each inference cycle):
```c
void chronion_record_activity(uint8_t hour) {
    g_chronion.activity_heatmap[hour]++;
    // Detect peak hour: find slot > 2x mean
    uint32_t total = 0;
    for (int i = 0; i < 24; i++) total += g_chronion.activity_heatmap[i];
    uint32_t mean = total / 24;
    for (int i = 0; i < 24; i++) {
        if (g_chronion.activity_heatmap[i] > mean * 2)
            orchestrion_hint_peak_hour(i); // proactive task scheduling
    }
}
```

REPL commands: /time (current TSC-based uptime), /uptime (formatted h:m:s since boot_tsc), /history (dump activity_heatmap as ASCII bar chart). continuity_epoch is preserved in soma_dna.bin so the organism knows how long it has existed across all reboots.
